import { DoorOpenIcon } from 'lucide-react';
import { cookies } from 'next/headers';
import { redirect } from 'next/navigation';
export default function LogoutButton() {
  async function logout() {
    'use server';

    const cookieStore = await cookies();

    cookieStore.delete('token');

    redirect('/');
  }

  return (
    <button
      className="flex cursor-pointer items-center gap-2 border border-gray/10 p-2 font-semibold transition-colors duration-300 hover:bg-gray hover:text-white dark:border-white/10 dark:hover:bg-white dark:hover:text-gray text-sm"
      onClick={logout}
    >
      <DoorOpenIcon size={18} />
      Logout
    </button>
  );
}
